mapper.select:
SELECT o.*, u.nickname as user_name FROM order_info o LEFT JOIN sys_user u ON o.user_id = u.id
AND o.user_id = #{userId}
AND o.status = #{status}
AND o.order_no LIKE CONCAT('%', #{orderNo}, '%')
ORDER BY o.create_time DESC

SELECT DATE(create_time) as date, COUNT(*) as order_count, SUM(pay_amount) as total_amount FROM order_info WHERE status IN (1, 2, 3)
AND create_time >= #{startTime}
AND create_time <= #{endTime}
GROUP BY DATE(create_time) ORDER BY date

SELECT oi.product_id, oi.product_name, SUM(oi.quantity) as sales_count,
       SUM(oi.total_price) as sales_amount
FROM order_item oi
INNER JOIN order_info o ON oi.order_id = o.id
WHERE o.status IN (1, 2, 3)

    AND o.create_time >= #{startTime}


    AND o.create_time <= #{endTime}

GROUP BY oi.product_id, oi.product_name
ORDER BY sales_count DESC
LIMIT #{limit}

SELECT c.name as category_name, SUM(oi.quantity) as sales_count, SUM(oi.total_price) as sales_amount FROM order_item oi INNER JOIN order_info o ON oi.order_id = o.id INNER JOIN product p ON oi.product_id = p.id INNER JOIN product_category c ON p.category_id = c.id WHERE o.status IN (1, 2, 3)
AND o.create_time >= #{startTime}
AND o.create_time <= #{endTime}
GROUP BY c.id, c.name ORDER BY sales_amount DESC

SELECT status, COUNT(*) as count
FROM order_info


        AND create_time >= #{startTime}


        AND create_time <= #{endTime}


GROUP BY status
ORDER BY status
